class DeviceController:
    def __init__(self, pin_no=2, active_high=True):
        self.pin = machine.Pin(pin_no, machine.Pin.OUT)
        self.active_high = active_high
        self.state = False
        self._apply()

    def _apply(self):
        val = 1 if self.state else 0
        if not self.active_high:
            val = 0 if val else 1
        self.pin.value(val)

    def turn_on(self):
        self.state = True
        self._apply()

    def turn_off(self):
        self.state = False
        self._apply()

    def toggle(self):
        self.state = not self.state
        self._apply()

    def get_status(self):
        return {"power": "on" if self.state else "off"}


